class Solution {
public:
    vector<string> removeSubfolders(vector<string>& folder) {
        sort(folder.begin(), folder.end());
        vector<string> res;
        for (const auto& f : folder) {
            if (res.empty() || res.back() + "/" != f.substr(0, res.back().size() + 1)) {
                res.push_back(f);
            }
        }
        return res;
    }
};

